import (
	"container/heap"
)

type PQElement struct {
	time int64
	node int64
}

type PriorityQueue []*PQElement

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool { return pq[i].time < pq[j].time }

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}

func (pq *PriorityQueue) Push(x interface{}) {
	item := x.(*PQElement)
	*pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

func solve(n int64, edges [][]int64) int64 {
	adj := make([][]struct{ v, s, e int64 }, n)
	for _, e := range edges {
		u := e[0]
		v := e[1]
		s := e[2]
		e_ := e[3]
		adj[u] = append(adj[u], struct{ v, s, e int64 }{v, s, e_})
	}

	dist := make([]int64, n)
	for i := range dist {
		dist[i] = -1
	}
	dist[0] = 0

	pq := make(PriorityQueue, 0)
	heap.Init(&pq)
	heap.Push(&pq, &PQElement{time: 0, node: 0})

	for pq.Len() > 0 {
		current := heap.Pop(&pq).(*PQElement)
		t := current.time
		u := current.node

		if u == n-1 {
			return t
		}

		if t > dist[u] {
			continue
		}

		for _, edge := range adj[u] {
			v := edge.v
			s := edge.s
			e := edge.e

			earliest := t
			if s > t {
				earliest = s
			}

			if earliest > e {
				continue
			}

			new_time := earliest + 1
			if dist[v] == -1 || new_time < dist[v] {
				dist[v] = new_time
				heap.Push(&pq, &PQElement{time: new_time, node: v})
			}
		}
	}

	return -1
}
